import { deriveCapabilities } from "../model/capabilities.js";
import { buildCommandsIndex } from "../model/command-index.js";
import { buildCommandModel } from "../model/command-model.js";
import { planOperations } from "../model/naming.js";
import { buildSchemaOutput } from "../model/schema.js";
import { listAuthSchemes } from "../parse/auth-schemes.js";
import { indexOperations } from "../parse/operations.js";
import { listServers } from "../parse/servers.js";
import { loadSpec } from "../spec/loader.js";
export async function buildRuntimeContext(options) {
    const loaded = await loadSpec({
        spec: options.spec,
        embeddedSpecText: options.embeddedSpecText,
        fs: options.fs,
    });
    const operations = indexOperations(loaded.doc);
    const servers = listServers(loaded.doc);
    const authSchemes = listAuthSchemes(loaded.doc);
    const planned = planOperations(operations);
    const commands = buildCommandModel(planned, {
        specId: loaded.id,
        globalSecurity: loaded.doc.security,
        authSchemes,
    });
    const commandsIndex = buildCommandsIndex(commands);
    const capabilities = deriveCapabilities({
        doc: loaded.doc,
        servers,
        authSchemes,
        operations,
        commands,
    });
    const schema = buildSchemaOutput(loaded, operations, planned, servers, authSchemes, commands, commandsIndex, capabilities);
    return {
        loaded,
        operations,
        servers,
        authSchemes,
        planned,
        commands,
        commandsIndex,
        capabilities,
        schema,
    };
}

import { summarizeAuth } from "../parse/auth-requirements.js";
import { deriveParamSpecs } from "../parse/params.js";
import { deriveFlags, derivePositionals, } from "../parse/positional.js";
import { deriveRequestBodyInfo, } from "../parse/request-body.js";
import { buildCommandId } from "./command-id.js";
export function buildCommandModel(planned, options) {
    const byResource = new Map();
    for (const op of planned) {
        const list = byResource.get(op.resource) ?? [];
        const params = deriveParamSpecs(op);
        const positionals = derivePositionals({ pathArgs: op.pathArgs, params });
        const flags = deriveFlags({ pathArgs: op.pathArgs, params });
        list.push({
            id: buildCommandId({
                specId: options.specId,
                resource: op.resource,
                action: op.action,
                operationKey: op.key,
            }),
            key: op.key,
            action: op.action,
            pathArgs: op.pathArgs,
            rawPathArgs: op.rawPathArgs,
            method: op.method,
            path: op.path,
            operationId: op.operationId,
            tags: op.tags,
            summary: op.summary,
            description: op.description,
            deprecated: op.deprecated,
            style: op.style,
            params,
            positionals,
            flags: flags.flags,
            auth: summarizeAuth(op.security, options.globalSecurity, options.authSchemes ?? []),
            requestBody: deriveRequestBodyInfo(op),
            requestBodySchema: deriveRequestBodyInfo(op)?.preferredSchema,
        });
        byResource.set(op.resource, list);
    }
    const resources = [];
    for (const [resource, actions] of byResource.entries()) {
        actions.sort((a, b) => {
            if (a.action !== b.action)
                return a.action.localeCompare(b.action);
            if (a.path !== b.path)
                return a.path.localeCompare(b.path);
            return a.method.localeCompare(b.method);
        });
        resources.push({ resource, actions });
    }
    resources.sort((a, b) => a.resource.localeCompare(b.resource));
    return { resources };
}

