export function getSchemaType(schema) {
    if (!schema || typeof schema !== "object")
        return "unknown";
    const t = schema.type;
    if (t === "string")
        return "string";
    if (t === "number")
        return "number";
    if (t === "integer")
        return "integer";
    if (t === "boolean")
        return "boolean";
    if (t === "array")
        return "array";
    if (t === "object")
        return "object";
    return "unknown";
}
export function getSchemaFormat(schema) {
    if (!schema || typeof schema !== "object")
        return undefined;
    const f = schema.format;
    return typeof f === "string" ? f : undefined;
}
export function getSchemaEnumStrings(schema) {
    if (!schema || typeof schema !== "object")
        return undefined;
    const e = schema.enum;
    if (!Array.isArray(e))
        return undefined;
    // We only surface string enums for now (enough for flag docs + completion).
    const values = e.filter((v) => typeof v === "string");
    return values.length ? values : undefined;
}

